    "Craftsmen": 25,
    "Farmers": 25
  },
  "trade_routes": [
    {
      "route_name": "Forest Path of Eldoria",
      "description": "A winding path through the Thalorion Forest used for trade and communication between villages."
    }
  ],
  "black_market_goods": [
    "Rare Alchemical Ingredients",
    "Forged Documents",
    "Stolen Artifacts from Malakai"
